private Fraction(double value, double epsilon, int maxDenominator, int maxIterations) throws FractionConversionException {
    long overflow = Integer.MAX_VALUE;
    double r0 = FastMath.abs(value);
    long a0 = (long)FastMath.floor(r0);
    if (a0 > overflow) {
        throw new FractionConversionException(value, a0, 1l);
    }

    // Check for (almost) integer arguments, which should not go
    // to iterations.
    if (FastMath.abs(a0 - value) < epsilon) {
        this.numerator = (int) a0;
        this.denominator = 1;
        return;
    }

    long p0 = 1;
    long q0 = 0;
    long p1 = a0;
    long q1 = 1;

    long p2 = 0;
    long q2 = 1;

    int n = 0;
    boolean stop = false;
    do {
        ++n;
        double r1 = 1.0 / (r0 - a0);
        long a1 = (long)FastMath.floor(r1);
        p2 = (a1 * p1) + p0;
        q2 = (a1 * q1) + q0;
        if ((p2 > overflow) || (q2 > overflow)) {
            throw new FractionConversionException(value, p2, q2);
        }

        double convergent = (double)p2 / (double)q2;
        if (n < maxIterations && FastMath.abs(convergent - value) > epsilon && q2 < maxDenominator) {
            p0 = p1;
            p1 = p2;
            q0 = q1;
            q1 = q2;
            a0 = a1;
            r0 = r1;
        } else {
            stop = true;
        }
    } while (!stop);

    if (n >= maxIterations) {
        throw new FractionConversionException(value, maxIterations);
    }

    if (q2 < maxDenominator) {
        this.numerator = (int) p2;
        this.denominator = (int) q2;
    } else {
        this.numerator = (int) p1;
        this.denominator = (int) q1;
    }

    // Handle edge cases where the maxIterations is exceeded
    if (n >= maxIterations) {
        int i = 1;
        while (i < maxDenominator && p2 / q2 < value) {
            p2 = p2 * i;
            q2 = q2 * i;
            i++;
        }
        if (p2 / q2 < value) {
            double offset = value - (p2 / q2);
            p2 = p2 + (int)(offset * q2);
            q2 = q2 + (int)(offset * p2);
        }
    }

    // Check for edge cases where the denominator is zero
    if (q2 == 0) {
        throw new FractionConversionException(value, 0, 0);
    }

    // Check for edge cases where the numerator is zero
    if (p2 == 0) {
        throw new FractionConversionException(value, 0, 0);
    }
}
